/// <reference types="vite/client" />

// This file provides TypeScript with type definitions for Vite-specific
// features, such as `import.meta.env` for environment variables.
//
// You can define frontend environment variables in a `.env` file
// in the frontend/ directory. They MUST be prefixed with VITE_ to be
// exposed to the browser (e.g., VITE_CUSTOM_RPC_URL=https://...).
//
// Example:
//   interface ImportMetaEnv {
//     readonly VITE_CUSTOM_RPC_URL: string
//   }
